import React from 'react';
import List from '@material-ui/core/List';
import ListItem from '@material-ui/core/ListItem';
import ListItemText from '@material-ui/core/ListItemText';
import { Link } from 'react-router-dom';

const DrawerMenu = ({ categories }) => {
  // Kontrollera om categories är definierat innan du mappar över det
  const generateMenuItems = () => {
    if (!categories) {
      return null;
    }

    return categories.map((category) => (
      <List key={category._id} component="nav">
        <ListItem button component={Link} to={`/${category.mainMenu}`}>
          <ListItemText primary={category.mainMenu} />
        </ListItem>
        {category.subMenu.length > 0 && (
          <List component="div" disablePadding>
            {category.subMenu.map((subItem) => (
              <ListItem
                key={subItem._id}
                button
                component={Link}
                to={`/${category.mainMenu}/${subItem}`}
                style={{ paddingLeft: 16 }}
              >
                <ListItemText primary={subItem} />
              </ListItem>
            ))}
          </List>
        )}
      </List>
    ));
  };

  return <div>{generateMenuItems()}</div>;
};

export default DrawerMenu;
